// Build the full personalized HTML email with the plan
const d = $input.first().json;

// Helper to escape HTML in text blocks
function esc(str) {
  return String(str || '')
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;');
}

// Convert the plain-text plan into styled HTML blocks
function planToHtml(text) {
  if (!text) return '';
  return text
    .split('\n')
    .map(line => {
      // Section headers with ══ or ━━
      if (/^[══━━]{6,}/.test(line)) return `<hr style="border:0;border-top:1px solid #1d3d4a;margin:12px 0">`;
      // Meal headers 🍽
      if (line.startsWith('🍽')) return `<p style="margin:14px 0 2px;font-weight:700;color:#5bd4ff;font-size:0.95rem">${esc(line)}</p>`;
      // Day headers 📅
      if (line.startsWith('📅')) return `<p style="margin:16px 0 4px;font-weight:800;color:#5bd4ff">${esc(line)}</p>`;
      // Summary rows with |
      if (line.trim().startsWith('|')) return `<p style="margin:2px 0;font-family:monospace;font-size:0.82rem;color:#8aa4af">${esc(line)}</p>`;
      // Bullet items with -
      if (/^\s+-\s/.test(line)) return `<p style="margin:2px 0 2px 16px;color:#c8dce6;font-size:0.88rem">${esc(line.trim().replace(/^-\s/,''))}</p>`;
      // Option headers *
      if (/^\s+\*\s/.test(line)) return `<p style="margin:8px 0 2px 8px;font-weight:700;color:#e2edf2">${esc(line.trim().replace(/^\*\s/,''))}</p>`;
      // Stat lines with :
      if (/:/.test(line) && line.trim() !== '') return `<p style="margin:3px 0;font-size:0.88rem;color:#c8dce6">${esc(line)}</p>`;
      // Empty lines
      if (line.trim() === '') return '<br>';
      return `<p style="margin:3px 0;color:#e2edf2">${esc(line)}</p>`;
    })
    .join('\n');
}

const mealHtml    = planToHtml(d.meal_plan_text);
const workoutHtml = planToHtml(d.workout_plan_text);

// Compute expected timeline label
const kgPerMonth = d.kg_to_lose > 0
  ? Math.round(d.deficit / 7700 * 30 * 10) / 10
  : null;
const timelineHtml = kgPerMonth
  ? `<p style="color:#8aa4af;font-size:0.88rem;margin:4px 0">בקצב הנוכחי: ~${kgPerMonth} ק"ג לחודש</p>`
  : '';

const fullHtml = `
